const hl7 = require('hl7'); // optional if available; manual parsing fallback

// Input data
const inputData = $input.first().json.body;
let parsed = { type: null, data: null, raw: inputData };

// Detect HL7 (pipe-separated, typical MSH segment)
if (typeof inputData === 'string' && (inputData.startsWith('MSH') || inputData.includes('\nMSH'))) {
  // Simple HL7 to JSON
  const segments = inputData.split(/\r?\n/);
  const hl7Json = { segments: [] };
  for (const seg of segments) {
    const fields = seg.split('|');
    hl7Json.segments.push({ name: fields[0], fields: fields.slice(1) });
  }
  parsed.type = 'HL7';
  parsed.data = hl7Json;
  parsed.patientId = hl7Json.segments.find(s => s.name === 'PID')?.fields[2] || 'unknown';
} else if (typeof inputData === 'object' && (inputData.resourceType || inputData.entry)) {
  // FHIR resource or bundle
  parsed.type = 'FHIR';
  parsed.data = inputData;
  parsed.patientId = inputData.id || (inputData.subject?.reference) || 'unknown';
} else {
  throw new Error('Unsupported format. Please send HL7 string or FHIR JSON.');
}

// Extract condition/problem for LLM context
let clinicalContext = '';
if (parsed.type === 'HL7') {
  const obxSegments = parsed.data.segments.filter(s => s.name === 'OBX');
  clinicalContext = obxSegments.map(s => s.fields[4] || '').join(', ');
} else if (parsed.type === 'FHIR') {
  if (parsed.data.resourceType === 'Condition') {
    clinicalContext = parsed.data.code?.text || parsed.data.code?.coding?.[0]?.display || '';
  } else if (parsed.data.entry) {
    const conditionEntry = parsed.data.entry.find(e => e.resource?.resourceType === 'Condition');
    clinicalContext = conditionEntry?.resource?.code?.text || '';
  }
}

return {
  parsed,
  clinicalContext: clinicalContext || 'No specific condition found.',
  patientId: parsed.patientId
};

