const llmOutput = $input.first().json.message.content;

// Guardrail violation patterns
const forbiddenPatterns = [
  /guarantee/i,
  /100% cure/i,
  /will definitely/i,
  /always safe/i,
  /no side effects/i,
  /diagnose you with/i,
  /prescribe/i,
  /take this medication/i
];

let isSafe = true;
let violations = [];
for (const pattern of forbiddenPatterns) {
  if (pattern.test(llmOutput)) {
    isSafe = false;
    violations.push(pattern.source);
  }
}

let finalOutput = llmOutput;
if (!isSafe) {
  finalOutput = "[GUARDRAIL ACTIVATED] The generated response contained potentially unsafe content. Please consult a licensed healthcare provider directly.\n\nOriginal violations: " + violations.join(", ");
}

return {
  originalLlmResponse: llmOutput,
  guardrailPassed: isSafe,
  finalResponse: finalOutput,
  violationsDetected: violations
};
